import json

def execute(inputs):
    """Emit final execution plan, separating build items from executable skills."""
    execution_plan = inputs.get('execution_plan', [])
    if isinstance(execution_plan, str):
        execution_plan = json.loads(execution_plan)

    build_items = []
    skill_ids = []
    for item in execution_plan:
        if item.get('action') == 'build_new_skill':
            build_items.append(item)
        elif item.get('action') == 'execute_existing':
            skill_ids.append(item['skill_id'])

    return {
        'plan': execution_plan,
        'build_items': build_items,
        'skill_ids': skill_ids
    }

outputs = execute(inputs)

