def test_emit_plan_empty():
    result = execute({'execution_plan': []})
    assert result['plan'] == []
    assert result['build_items'] == []
    assert result['skill_ids'] == []

def test_emit_plan_mixed():
    plan = [
        {'action': 'execute_existing', 'skill_id': 's1', 'sub_objective': 'a'},
        {'action': 'build_new_skill', 'sub_objective': 'b', 'context': {}}
    ]
    result = execute({'execution_plan': plan})
    assert len(result['skill_ids']) == 1
    assert len(result['build_items']) == 1
